export class Debug {
    static onMessage(listener) {
        this.listeners.push(listener);
    }
    static emit(type, text) {
        const msg = {
            type,
            text,
            timestamp: new Date()
        };
        for (const listener of this.listeners) {
            listener(msg);
        }
        // Optional: still log to browser console
        if (type === "log")
            console.log(text);
        if (type === "warn")
            console.warn(text);
        if (type === "error")
            console.error(text);
    }
    static log(text) {
        this.emit("log", text);
    }
    static warn(text) {
        this.emit("warn", text);
    }
    static error(text) {
        this.emit("error", text);
    }
}
Debug.listeners = [];
